        dtypeSetLogicSized(bitwidth, VSigning::UNSIGNED);
    }
    AstSel(FileLine* fl, AstNodeExpr* fromp, int lsb, int bitwidth)
        : ASTGEN_SUPER_Sel(fl, fromp, new AstConst(fl, lsb))  // Need () constructor
