    void visit(AstBasicDType* nodep) override {
        // Check for void type used in tagged unions
        if (nodep->keyword() == VBasicDTypeKwd::CVOID) {
            nodep->v3warn(E_UNSUPPORTED, "Unsupported: void (for tagged unions)");
        }
        cleanFileline(nodep);
