    void visit(AstToLowerN* nodep) override {
        assertAtExpr(nodep);
        if (m_vup->prelim()) {
            iterateCheckString(nodep, "LHS", nodep->lhsp(), BOTH);
            nodep->dtypeSetString();
        }
