  endfunction

  sub sub(.*);

  initial begin
    int other;
    begin //unnamed
      for (int i = 0; i < 3; ++i) begin
        other = f(i);
        $display("stmt %d %d", i, other);
        t();
      end
    end
    begin : named
      $display("stmt");
    end : named
  end
  final begin
    $display("stmt");
  end

  always @ (in) begin
    $display("stmt");
  end
  always @ (posedge clk) begin
    $display("posedge clk");
    pubflat_r <= pubflat_w;
  end
  always @ (negedge clk) begin
    $display("negedge clk, pfr = %x", pubflat_r);
  end

  int cyc;
  int fo;
  int sum;
  real r;
  string str;
  int mod_val;
  int mod_res;
  always_ff @ (posedge clk) begin
    cyc <= cyc + 1;
    r <= r + 0.01;
    fo = cyc;
    sub.inc(fo, sum);
    sum = sub.f(sum);
    $display("[%0t] sum = %d", $time, sum);
    $display("a?= %d", $c(1) ? $c32(20) : $c32(30));

    $c(";");
    $display("%d", $c("0"));
    fd = $fopen("/dev/null");
    $fclose(fd);
    fd = $fopen("/dev/null", "r");
    $fgetc(fd);  //  stmt
